    match set_cli.command {
        Commands::Props {
            props_command: PropsCommands::Set { path, value },
        } => {
            assert_eq!(path, "gateway.port");
            assert_eq!(value.as_deref(), Some("9090"));
        }
        other => panic!("expected props set command, got {other:?}"),
    }

    let get_cli = Cli::try_parse_from(["zeroclaw", "props", "get", "gateway.port"])
        .expect("props get should parse");
    match get_cli.command {
        Commands::Props {
            props_command: PropsCommands::Get { path },
        } => assert_eq!(path, "gateway.port"),
        other => panic!("expected props get command, got {other:?}"),
    }

    let list_cli = Cli::try_parse_from(["zeroclaw", "props", "list", "--filter", "gateway"])
        .expect("props list should parse");
    match list_cli.command {
        Commands::Props {
            props_command: PropsCommands::List { filter, secrets },
        } => {
            assert_eq!(filter.as_deref(), Some("gateway"));
            assert!(!secrets);
        }
        other => panic!("expected props list command, got {other:?}"),
    }
}

#[test]
fn props_config_roundtrip_sets_scalar_property() {
    let mut config = Config::default();
    config
        .set_prop("gateway.port", "9090")
        .expect("gateway.port should be settable");

    assert_eq!(config.gateway.port, 9090);
    assert_eq!(
        config
            .get_prop("gateway.port")
            .expect("gateway.port should be readable"),
        "9090"
    );
}

#[test]
fn props_config_hides_secret_values() {
    let mut config = Config::default();
    config
        .set_prop("api_key", "sk-test-props")
        .expect("api_key should be settable");

    assert!(config.prop_is_secret("api_key"));
    assert_eq!(
        config
            .get_prop("api_key")
            .expect("api_key secret status should be readable"),
        "<set>"
    );
}

