use crate::config::Config;
use anyhow::{Context, Result, bail};
use serde_json::Value;

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum PropKind {
    Bool,
    Integer,
    Float,
    String,
    Array,
    Object,
    Unknown,
}

impl PropKind {
    pub const fn as_str(self) -> &'static str {
        match self {
            Self::Bool => "bool",
            Self::Integer => "integer",
            Self::Float => "float",
            Self::String => "string",
            Self::Array => "array",
            Self::Object => "object",
            Self::Unknown => "unknown",
        }
    }
}

#[derive(Debug, Clone)]
pub struct PropField {
    pub path: String,
    pub kind: PropKind,
    pub secret: bool,
}

const SECRET_SUFFIXES: &[&str] = &[
    "api_key",
    "app_secret",
    "access_token",
    "auth_token",
    "bearer_token",
    "bot_token",
    "client_secret",
    "db_url",
    "encrypt_key",
    "oauth_token",
    "password",
    "private_key",
    "recovery_key",
    "sasl_password",
    "server_password",
    "signing_secret",
    "token",
    "verification_token",
    "verify_token",
    "webhook_key",
    "webhook_secret",
];

fn path_segments(path: &str) -> Result<Vec<&str>> {
    let trimmed = path.trim();
    if trimmed.is_empty() {
        bail!("property path must not be empty");
    }
    let segments: Vec<_> = trimmed.split('.').collect();
    if segments.iter().any(|segment| segment.is_empty()) {
        bail!("property path must not contain empty segments");
    }
    Ok(segments)
}

fn value_at_path<'a>(value: &'a Value, path: &str) -> Result<&'a Value> {
    let mut current = value;
    for segment in path_segments(path)? {
        current = current
            .as_object()
            .and_then(|object| object.get(segment))
            .with_context(|| format!("unknown config property: {path}"))?;
    }
    Ok(current)
}

fn value_at_path_mut<'a>(value: &'a mut Value, path: &str) -> Result<&'a mut Value> {
    let segments = path_segments(path)?;
    let mut current = value;
    for segment in segments {
        current = current
            .as_object_mut()
            .and_then(|object| object.get_mut(segment))
            .with_context(|| format!("unknown config property: {path}"))?;
    }
    Ok(current)
}

fn kind_of(value: &Value) -> PropKind {
    match value {
        Value::Bool(_) => PropKind::Bool,
        Value::Number(number) if number.is_f64() => PropKind::Float,
        Value::Number(_) => PropKind::Integer,
        Value::String(_) => PropKind::String,
        Value::Array(_) => PropKind::Array,
        Value::Object(_) => PropKind::Object,
        Value::Null => PropKind::Unknown,
    }
}

fn parse_value(input: &str, current: &Value) -> Result<Value> {
    Ok(match current {
        Value::Bool(_) => Value::Bool(input.parse::<bool>().with_context(|| {
            format!("expected boolean value for property, got {input:?}")
        })?),
        Value::Number(number) if number.is_f64() => serde_json::Number::from_f64(
            input
                .parse::<f64>()
                .with_context(|| format!("expected float value for property, got {input:?}"))?,
        )
        .map(Value::Number)
        .context("float value must be finite")?,
        Value::Number(number) if number.is_u64() => {
            Value::Number(input.parse::<u64>().with_context(|| {
                format!("expected unsigned integer value for property, got {input:?}")
            })?.into())
        }
        Value::Number(_) => Value::Number(input.parse::<i64>().with_context(|| {
            format!("expected integer value for property, got {input:?}")
        })?.into()),
        Value::String(_) => Value::String(input.to_string()),
        Value::Null => {
            if input.is_empty() {
                Value::Null
            } else {
                Value::String(input.to_string())
            }
        }
        Value::Array(_) | Value::Object(_) => serde_json::from_str(input)
            .context("array and object properties must be set from JSON input")?,
    })
}

fn collect_props(prefix: &str, value: &Value, props: &mut Vec<PropField>) {
    match value {
        Value::Object(object) => {
            for (key, child) in object {
                let path = if prefix.is_empty() {
                    key.clone()
                } else {
                    format!("{prefix}.{key}")
                };
                collect_props(&path, child, props);
            }
        }
        _ => props.push(PropField {
            path: prefix.to_string(),
            kind: kind_of(value),
            secret: prop_path_is_secret(prefix),
        }),
    }
}

fn prop_path_is_secret(path: &str) -> bool {
    let Some(last) = path.rsplit('.').next() else {
        return false;
    };
    SECRET_SUFFIXES.iter().any(|suffix| {
        last == *suffix || last.ends_with(&format!("_{suffix}")) || path.ends_with(&format!(".{suffix}"))
    })
}

fn display_value(value: &Value) -> Result<String> {
    Ok(match value {
        Value::Null => String::new(),
        Value::Bool(value) => value.to_string(),
        Value::Number(value) => value.to_string(),
        Value::String(value) => value.clone(),
        Value::Array(_) | Value::Object(_) => serde_json::to_string(value)?,
    })
}

impl Config {
    pub fn prop_fields(&self) -> Vec<PropField> {
        let value = serde_json::to_value(self).unwrap_or(Value::Null);
        let mut props = Vec::new();
        collect_props("", &value, &mut props);
        props.sort_by(|left, right| left.path.cmp(&right.path));
        props
    }

    pub fn prop_is_secret(&self, path: &str) -> bool {
        prop_path_is_secret(path)
    }

    pub fn get_prop(&self, path: &str) -> Result<String> {
        let value = serde_json::to_value(self).context("failed to serialize config")?;
        let current = value_at_path(&value, path)?;
        if self.prop_is_secret(path) {
            let is_set = match current {
                Value::Null => false,
                Value::String(value) => !value.is_empty(),
                Value::Array(value) => !value.is_empty(),
                _ => true,
            };
            return Ok(if is_set { "<set>" } else { "<unset>" }.to_string());
        }
        display_value(current)
    }

    pub fn set_prop(&mut self, path: &str, input: &str) -> Result<()> {
        let mut value = serde_json::to_value(&*self).context("failed to serialize config")?;
        let current = value_at_path(&value, path)?.clone();
        let target = value_at_path_mut(&mut value, path)?;
        *target = parse_value(input, &current)?;
        let updated: Self = serde_json::from_value(value).context("failed to deserialize updated config")?;
        *self = updated;
        Ok(())
    }
}

