    pub fn get_prop(&self, path: &str) -> Result<String> {
        let value = serde_json::to_value(self).context("failed to serialize config")?;
        let current = value_at_path(&value, path)?;
        if self.prop_is_secret(path) {
            let is_set = match current {
                Value::Null => false,
                Value::String(value) => !value.is_empty(),
                Value::Array(value) => !value.is_empty(),
                _ => true,
            };
            return Ok(if is_set { "<set>" } else { "<unset>" }.to_string());
        }
        display_value(current)
    }

    pub fn set_prop(&mut self, path: &str, input: &str) -> Result<()> {
        let mut value = serde_json::to_value(&*self).context("failed to serialize config")?;
        let current = value_at_path(&value, path)?.clone();
        let target = value_at_path_mut(&mut value, path)?;
        *target = parse_value(input, &current)?;
        let updated: Self = serde_json::from_value(value).context("failed to deserialize updated config")?;
        *self = updated;
        Ok(())
    }
}

