            "onboard",
            "--provider",
            "openrouter",
            "--model",
            "custom-model-946",
            "--api-key",
            "sk-issue946",
        ])
        .expect("quick onboard invocation should parse");

        match cli.command {
            Commands::Onboard {
                force,
                channels_only,
                api_key,
                provider,
                model,
                ..
            } => {
                assert!(!force);
                assert!(!channels_only);
                assert_eq!(provider.as_deref(), Some("openrouter"));
                assert_eq!(model.as_deref(), Some("custom-model-946"));
                assert_eq!(api_key.as_deref(), Some("sk-issue946"));
            }
            other => panic!("expected onboard command, got {other:?}"),
        }
    }

    #[test]
    fn completions_cli_parses_supported_shells() {
        for shell in ["bash", "fish", "zsh", "powershell", "elvish"] {
            let cli = Cli::try_parse_from(["zeroclaw", "completions", shell])
                .expect("completions invocation should parse");
            match cli.command {
                Commands::Completions { .. } => {}
                other => panic!("expected completions command, got {other:?}"),
            }
        }
    }

    #[test]
    fn completion_generation_mentions_binary_name() {
        let mut output = Vec::new();
        write_shell_completion(CompletionShell::Bash, &mut output)
            .expect("completion generation should succeed");
        let script = String::from_utf8(output).expect("completion output should be valid utf-8");
        assert!(
            script.contains("zeroclaw"),
            "completion script should reference binary name"
        );
    }

    #[test]
    fn props_cli_parses_set_get_and_list() {
        let set_cli = Cli::try_parse_from(["zeroclaw", "props", "set", "gateway.port", "9090"])
            .expect("props set should parse");
        match set_cli.command {
            Commands::Props {
                props_command: PropsCommands::Set { path, value },
            } => {
                assert_eq!(path, "gateway.port");
                assert_eq!(value.as_deref(), Some("9090"));
            }
            other => panic!("expected props set command, got {other:?}"),
        }

        let get_cli = Cli::try_parse_from(["zeroclaw", "props", "get", "gateway.port"])
            .expect("props get should parse");
        match get_cli.command {
            Commands::Props {
                props_command: PropsCommands::Get { path },
            } => assert_eq!(path, "gateway.port"),
            other => panic!("expected props get command, got {other:?}"),
        }

        let list_cli = Cli::try_parse_from(["zeroclaw", "props", "list", "--filter", "gateway"])
            .expect("props list should parse");
        match list_cli.command {
            Commands::Props {
                props_command: PropsCommands::List { filter, secrets },
            } => {
                assert_eq!(filter.as_deref(), Some("gateway"));
                assert!(!secrets);
            }
            other => panic!("expected props list command, got {other:?}"),
        }
    }

    #[test]
    fn props_config_roundtrip_sets_scalar_property() {
        let mut config = Config::default();
        config
            .set_prop("gateway.port", "9090")
            .expect("gateway.port should be settable");

        assert_eq!(config.gateway.port, 9090);
        assert_eq!(
            config
                .get_prop("gateway.port")
                .expect("gateway.port should be readable"),
            "9090"
        );
    }

